sp_widget.css:
.admin-page-topbar {
  display: flex;
  align-items: center;
  gap: 14px;
  margin-bottom: 24px;
  padding-bottom: 16px;
  border-bottom: 1px solid #e2e8f0;
}

.admin-back-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  border-radius: 50%;
  background: #ffffff;
  border: 1.5px solid #e2e8f0;
  cursor: pointer;
  color: #374151;
  flex-shrink: 0;
  transition: background 0.15s, border-color 0.15s;
}

.admin-back-btn:hover {
  background: #f1f5f9;
  border-color: #94a3b8;
}

.headd {
		font-size: 2.6rem;
    font-weight: 700;
    color: #0f172a;
}

.profile-header {
  display: flex;
  align-items: center;
  background: white;
  padding: 15px;
  //border: 1px solid #ddd;
  //border-bottom: 3px solid #f39c12;
  border-radius: 1rem;
  margin-bottom: 2rem;
}

.profile-left img {
  width: 80px;
  height: 80px;
  border-radius: 6px;
  object-fit: cover;
}

.profile-left {
  margin-right: 5.5rem;
}

.profile-center {
  flex: 1;
}

.profile-center h2 {
  margin: 0 0 10px 0;
  font-size: 1.6rem;
  font-weight: 600;
}

.info-grid {
  display: grid;
  grid-template-columns: repeat(2, auto);
  gap: 6px 40px;
  font-size: 1.6rem;
}

.profile-right {
  margin-left: 10px;
}

.icon-btn {
  background: #5bc0de;
  border: none;
  padding: 8px 10px;
  border-radius: 4px;
  color: white;
  cursor: pointer;
}

.icon-btn:hover {
  background: #31b0d5;
}

sp_widget.script:
(function() {

    var loggedInUser = gs.getUserID();

    // 🚫 Block unauthenticated users
    if (!loggedInUser) {
        data.error = "Unauthorized";
        return;
    }

    // ✅ Role check (user OR incentnow admin OR system admin)
    var hasAccessRole = gs.hasRole('x_ctans_incentnow.user');

    if (!hasAccessRole) {
        data.error = "Access Denied";
        return;
    }

    // 1. Get statement_id
    var statementId = $sp.getParameter('statement_id');

    if (!statementId) {
        data.error = "No statement_id in URL";
        return;
    }

    // 2. Fetch statement
    var stmtGR = new GlideRecordSecure('x_ctans_incentnow_incentive_statement');

    if (!stmtGR.get(statementId)) {
        data.error = "Statement record not found";
        return;
    }

    var statementUser = stmtGR.getValue('user');

    // 🔐 Record-level access
    var isOwner   = (statementUser == loggedInUser);
    var isManager = gs.hasRole('x_ctans_incentnow.manager');
    var isAdmin   = gs.hasRole('x_ctans_incentnow.admin');

    if (!isOwner && !isManager && !isAdmin) {
        data.error = "Access Denied";
        return;
    }

    // 3. Fetch user
    var userGR = new GlideRecordSecure('x_ctans_incentnow_user_profile');

    if (!userGR.get(statementUser)) {
        data.error = "User record not found";
        return;
    }

    // 4. Send safe data
    data.name = userGR.user.name.toString();
    data.user_name = userGR.user.user_name.toString();
    data.email = userGR.user.email.toString();
    data.title = userGR.user.title.toString();
    data.manager = userGR.user.manager.getDisplayValue();
    data.role = userGR.getDisplayValue('role');

    data.photo = userGR.user.photo ?
        '/sys_attachment.do?sys_id=' + userGR.user.photo :
        '';

})();
